(360001, 'homepageSectionHeaders', '{"services":{"title":"Digital Marketing Services Offered by Our Agency","description":"From Web Development and SEO Services to CRM Software and Social Media Marketing, we deliver customized digital solutions that help businesses grow, attract customers, and build a strong online presence.\\n"},"portfolio":{"title":"Our Website Portfolio","description":"Explore our website portfolio showcasing innovative, responsive, and user-friendly websites developed for businesses. From corporate websites to eCommerce platforms, our projects reflect quality design, seamless functionality, and a commitment to helping brands grow online.\\n"},"techStack":{"title":"Our Technology Arsenal","description":"We use the latest technology stack to build robust and scalable solutions."},"latestBlog":{"title":"Digital Insights & Strategies","description":"Stay ahead of the curve with our latest articles and news."},"trust":{"title":"Why Leading Brands Trust Us","description":"We deliver results that matter to your bottom line."},"faq":{"title":"Frequently Asked Questions","description":"Everything you need to know about our services."}}'),
(390001, 'policy_refund', '{"title":"Refund Policy","content":"At Global Webify, we are committed to providing high-quality digital services and ensuring customer satisfaction. Before starting any project, we clearly discuss the scope of work, requirements, timelines, and deliverables with our clients.<br/><br/>\\n\\n<b>No Refund Policy</b><br/>\\n\\nOnce the project has been started and resources, time, or efforts have been invested, the payment made by the client will be considered non-refundable.<br/><br/>\\n\\nIf a client decides to discontinue, cancel, or quit the project after the work has started, no refund will be provided for the amount already paid.<br/><br/>\\n\\n<b>Project Cancellation</b><br/>\\n\\nClients may request project cancellation; however, any completed work, delivered services, or resources allocated until the cancellation date will not be eligible for a refund.<br/><br/>\\n\\n<b>Service Commitment</b><br/>\\n\\nWe always aim to deliver the agreed services as per the project requirements. Clients are requested to review all details carefully before making payments and approving project commencement.<br/><br/>\\n\\n<b>Payment Terms</b><br/>\\n\\nPayments made for website development, SEO services, digital marketing, software development, or any other services are non-refundable once the work process begins.<br/><br/>\\n\\nFor any questions regarding our Refund Policy, please contact our support team.","updatedAt":"June 19, 2026"}'),
(390002, 'policy_return', '{"title":"Return Policy","content":"At Global Webify, we are committed to providing high-quality digital products and services to our clients. Due to the nature of our services, including software development, web development, SEO, digital marketing, CRM solutions, and other customized digital solutions, all purchases are considered final.<br/><br/>\\n\\nIf you decide to discontinue, cancel, or quit our product or service after the order confirmation or project initiation, no return, refund, or replacement will be provided.<br/><br/>\\n\\nBefore starting any project or service, we ensure clear communication regarding requirements, scope, pricing, and deliverables. Clients are requested to review all details carefully before confirming their order.<br/><br/>\\n\\nIn case of any concerns or issues related to our services, our support team will assist you and try to resolve the matter as per the agreed terms and conditions. However, cancellation of services after commencement will not qualify for any return or refund.<br/><br/>\\n\\nBy purchasing our products or services, you agree to our Return Policy and Terms & Conditions.","updatedAt":"June 19, 2026"}'),
(390003, 'policy_delivery', '{"title":"Delivery Policy","content":"At Global Webify, we ensure a smooth and transparent project delivery process. The final project, website, software, or digital solution will be delivered and made live only after the completion of all agreed payments or pending installments as per the project agreement.<br/><br/>\\n\\nOnce the complete payment has been received, we will provide the final deliverables, including project files, access details, and live deployment (where applicable). Before final delivery, the client will have the opportunity to review the project and confirm completion according to the agreed requirements.<br/><br/>\\n\\nIn case of installment-based projects, each milestone delivery will be managed according to the payment schedule and project terms. Any delay in payment may affect the project timeline and final delivery date.<br/><br/>\\n\\nWe are committed to delivering quality work, maintaining transparency, and ensuring a smooth handover process for every project.","updatedAt":"June 19, 2026"}');
